"use client";

import { useState, useRef, useEffect } from "react";
import { useLang } from "@/context/LangContext";
import { getVendor } from "@/lib/vendors";
import type { NewsItem } from "@/lib/types";

/** Small pill-shaped Listen button used on every story card AND the
 *  /story?id=… detail page. Plays the per-story TTS MP3 (EN or HE)
 *  generated by publish_data.py via edge-tts. Renders nothing when no
 *  audio URL is set for the active language — older archive stories
 *  will quietly omit the button until backfilled. */
export function StoryListenButton({ enUrl, heUrl, isHe, vendorColor }: {
  enUrl?: string; heUrl?: string; isHe: boolean; vendorColor: string;
}) {
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const url = isHe ? heUrl : enUrl;
  useEffect(() => {
    const a = audioRef.current;
    if (a) { a.pause(); a.currentTime = 0; }
    setIsPlaying(false);
  }, [isHe, url]);
  if (!url) return null;
  return (
    <>
      <button
        type="button"
        onClick={(e) => {
          e.stopPropagation();
          const a = audioRef.current;
          if (!a) return;
          if (a.paused) { a.play().catch(() => setIsPlaying(false)); setIsPlaying(true); }
          else { a.pause(); setIsPlaying(false); }
        }}
        aria-label={isPlaying ? (isHe ? "עצור" : "Pause") : (isHe ? "האזן לכתבה" : "Listen to story")}
        title={isHe ? "האזן לכתבה" : "Listen to story"}
        style={{
          display: "inline-flex", alignItems: "center", gap: "4px",
          padding: "2px 8px", borderRadius: "100px",
          border: `1px solid ${vendorColor}25`,
          background: isPlaying ? `${vendorColor}18` : `${vendorColor}08`,
          color: vendorColor,
          fontSize: "10px", fontWeight: 800, letterSpacing: "0.06em",
          cursor: "pointer", transition: "background 0.15s",
          flexShrink: 0,
        }}
      >
        <span style={{ fontSize: "9px", lineHeight: 1 }}>{isPlaying ? "⏸" : "▶"}</span>
        <span>{isHe ? "האזן" : "Listen"}</span>
      </button>
      <audio
        key={url}
        ref={audioRef}
        src={url}
        preload="none"
        onEnded={() => setIsPlaying(false)}
        onPause={() => setIsPlaying(false)}
        onPlay={() => setIsPlaying(true)}
      />
    </>
  );
}

/** Image with gradient fallback — uses React state to track load failures */
const GENERIC_LOGOS = ["arxiv-logo-twitter", "placeholder", "default-og"];

function OgImage({ src, vendor, vendorColor, height = "160px", width = "100%" }: { src?: string; vendor: string; vendorColor: string; height?: string; width?: string }) {
  const [failed, setFailed] = useState(false);
  const isGeneric = src && GENERIC_LOGOS.some((logo) => src.includes(logo));
  const validSrc = src && !failed && !isGeneric;

  return (
    <div style={{ width, height, minHeight: height === "100%" ? "100%" : undefined, overflow: "hidden", flexShrink: 0 }}>
      {validSrc ? (
        <img
          src={src}
          referrerPolicy="no-referrer"
          alt=""
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
          onError={() => setFailed(true)}
        />
      ) : (
        <FallbackGradient color={vendorColor} vendor={vendor} />
      )}
    </div>
  );
}

interface StoryCardProps {
  story: NewsItem;
  featured?: boolean;
  secondary?: boolean;
  sidebar?: boolean;
  rank?: number;
}

/** Renders a small "+ <Vendor>" badge next to the primary vendor when a story
 *  prominently involves two companies (e.g. Apple+Google for Gemini-Siri). */
function SecondaryVendorBadge({ name, size = "md" }: { name?: string; size?: "sm" | "md" }) {
  if (!name) return null;
  const v = getVendor(name);
  const iconBox = size === "sm" ? 18 : 22;
  const iconSize = size === "sm" ? 10 : 12;
  const fontPx = size === "sm" ? "9px" : "10px";
  return (
    <span className="inline-flex items-center gap-1.5">
      <span style={{ color: "#9a9ab8", fontSize: fontPx, fontWeight: 700 }}>+</span>
      <div
        style={{
          width: `${iconBox}px`,
          height: `${iconBox}px`,
          borderRadius: "6px",
          background: `linear-gradient(135deg, ${v.color}18, ${v.color}30)`,
          border: `1px solid ${v.color}25`,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: v.color,
          flexShrink: 0,
        }}
      >
        <CategoryIcon vendor={name} size={iconSize} />
      </div>
      <span
        className="inline-flex items-center font-black px-2 py-0.5 rounded-full uppercase"
        style={{
          color: v.color,
          background: v.bg,
          border: `1px solid ${v.color}20`,
          letterSpacing: "0.1em",
          fontSize: fontPx,
          cursor: "pointer",
        }}
        onClick={(e) => { e.stopPropagation(); filterByVendor(name); }}
      >
        {v.label}
      </span>
    </span>
  );
}

function isToday(publishedDate: string): boolean {
  const now = new Date();
  const months = ["january","february","march","april","may","june","july","august","september","october","november","december"];
  const m = publishedDate.toLowerCase().match(/(\w+)\s+(\d+),?\s+(\d{4})/);
  if (!m) return false;
  return months.indexOf(m[1]) === now.getMonth() && parseInt(m[2]) === now.getDate() && parseInt(m[3]) === now.getFullYear();
}

function getDomain(url: string): string {
  try {
    const u = new URL(url);
    return u.hostname.replace(/^www\./, "");
  } catch {
    return url;
  }
}

function filterByVendor(vendor: string) {
  window.dispatchEvent(new CustomEvent("filter-vendor", { detail: vendor }));
  window.scrollTo({ top: 0, behavior: "smooth" });
}

/** Bold gradient fallback with large centered vendor icon */
function FallbackGradient({ color, vendor }: { color: string; vendor: string }) {
  return (
    <div style={{
      width: "100%", height: "100%", position: "relative", overflow: "hidden",
      background: `linear-gradient(145deg, ${color}25 0%, ${color}10 50%, ${color}20 100%)`,
      display: "flex", alignItems: "center", justifyContent: "center",
    }}>
      {/* Background circle */}
      <div style={{
        position: "absolute",
        width: "130px", height: "130px", borderRadius: "50%",
        background: `${color}12`,
        border: `2px solid ${color}18`,
      }} />
      {/* Icon — large and prominent */}
      <div style={{ position: "relative", color, opacity: 0.6 }}>
        <CategoryIcon vendor={vendor} size={64} />
      </div>
    </div>
  );
}

