// ──────────────────────────────────────────────────────
// FEATURED CARD — Clean editorial hero (Bloomberg style)
// ──────────────────────────────────────────────────────
function FeaturedCard({ story }: { story: NewsItem }) {
  const { isHe } = useLang();
  const [expanded, setExpanded] = useState(false);
  const [clamped, setClamped] = useState(false);
  const summaryRef = useRef<HTMLParagraphElement>(null);
  const vendor = getVendor(story.vendor);
  const headline = isHe && story.headline_he ? story.headline_he : story.headline;
  const summary = isHe && story.summary_he ? story.summary_he : story.summary;
  useEffect(() => {
    const el = summaryRef.current;
    if (el) setClamped(el.scrollHeight > el.clientHeight);
  }, [summary]);
  return (
    <article
      id={`story-${story.story_id}`}
      className="group relative rounded-2xl overflow-hidden h-full flex flex-col story-card-hover"
      style={{
        background: "#ffffff",
        border: "1px solid #e0e0ec",
        boxShadow: "0 2px 12px rgba(0,0,0,0.06), 0 8px 32px rgba(0,0,0,0.04)",
        cursor: "pointer",
      }}
      onClick={() => window.location.href = `/story/${story.story_id}/`}
    >
      {/* Hero image or abstract gradient fallback */}
      <OgImage src={story.og_image} vendor={story.vendor} vendorColor={vendor.color} height="220px" />

      {/* Bold vendor color top bar */}
      <div
        style={{
          height: "5px",
          background: `linear-gradient(90deg, ${vendor.color} 0%, ${vendor.color}cc 60%, ${vendor.color}44 100%)`,
          flexShrink: 0,
        }}
      />

      {/* Content — generous padding, typography-first design */}
      <div className="flex flex-col gap-5 px-8 sm:px-10 py-8 flex-1">
        {/* Top row: category icon + vendor badge + sources */}
        <div className="flex items-center gap-2.5">
          {/* Colored icon square */}
          <div
            style={{
              width: "38px",
              height: "38px",
              borderRadius: "10px",
              background: `linear-gradient(135deg, ${vendor.color}18, ${vendor.color}30)`,
              border: `1px solid ${vendor.color}25`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: vendor.color,
              flexShrink: 0,
              boxShadow: `0 2px 8px ${vendor.color}18`,
            }}
          >
            <CategoryIcon vendor={story.vendor} size={20} />
          </div>

          <span
            className="inline-flex items-center text-[11px] font-black px-2.5 py-0.5 rounded-full uppercase"
            style={{
              color: vendor.color,
              background: vendor.bg,
              border: `1px solid ${vendor.color}20`,
              letterSpacing: "0.12em",
              cursor: "pointer",
            }}
            onClick={(e) => { e.stopPropagation(); filterByVendor(story.vendor); }}
          >
            {vendor.label}
          </span>
          <SecondaryVendorBadge name={story.secondary_vendor} />
          <StoryListenButton enUrl={story.summary_audio_url} heUrl={story.summary_audio_url_he} isHe={isHe} vendorColor={vendor.color} />

          {isToday(story.published_date) && (
            <span
              className="inline-flex items-center gap-1 text-[9px] font-black px-2 py-0.5 rounded-full uppercase"
              style={{
                color: "#dc2626",
                background: "rgba(220,38,38,0.08)",
                border: "1px solid rgba(220,38,38,0.18)",
                letterSpacing: "0.1em",
              }}
            >
              <span className="w-1.5 h-1.5 rounded-full shrink-0" style={{ backgroundColor: "#dc2626" }} />
              {isHe ? "חדש" : "NEW"}
            </span>
          )}

          {story.source_count >= 1 && (
            <span
              className="ml-auto inline-flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full"
              style={{
                color: "#16a34a",
                background: "rgba(22,163,74,0.08)",
                border: "1px solid rgba(22,163,74,0.18)",
              }}
            >
              <span
                className="w-1.5 h-1.5 rounded-full shrink-0"
                style={{ backgroundColor: "#16a34a" }}
              />
              {story.source_count} {isHe ? "מקורות" : "sources"}
            </span>
          )}
        </div>

        {/* Massive editorial headline */}
        <h2
          className="leading-tight transition-colors group-hover:text-indigo-600"
          style={{
            fontFamily: "var(--font-display, inherit)",
            fontSize: "clamp(22px, 2.5vw, 34px)",
            fontWeight: 700,
            color: "#0f0f1a",
            lineHeight: "1.06",
            letterSpacing: "-0.04em",
          }}
        >
          {headline}
        </h2>

        {/* Meta row */}
        <div className="flex items-center gap-3">
          <time
            className="text-[11px] font-semibold tabular-nums"
            style={{ color: "#9a9ab8", fontFamily: "monospace" }}
          >
            {story.published_date}
          </time>
        </div>

        {/* Summary — comfortable reading size, clamped to 5 lines until expanded */}
        <p
          ref={summaryRef}
          className="leading-relaxed flex-1"
          style={{
            fontSize: "15px",
            color: "#3d3d5a",
            lineHeight: "1.75",
            ...(expanded ? {} : {
              display: "-webkit-box",
              WebkitBoxOrient: "vertical" as const,
              WebkitLineClamp: 5,
              overflow: "hidden",
            }),
          }}
        >
          {summary}
        </p>
        {(clamped || expanded) && (
          <button
            onClick={(e) => { e.stopPropagation(); setExpanded((v) => !v); }}
            className="text-[12px] font-bold self-start"
            style={{ color: vendor.color, background: "none", border: "none", cursor: "pointer", padding: 0 }}
          >
            {expanded ? (isHe ? "הצג פחות" : "Show less") : (isHe ? "קרא עוד" : "Read more")}
          </button>
        )}

        {/* Source links */}
        {story.urls && story.urls.length > 0 && (
          <div
            className="flex flex-wrap gap-x-3 gap-y-1 pt-4 mt-auto"
            style={{ borderTop: "1px solid #ededf5" }}
          >
            {story.urls.slice(0, 4).map((url, i) => (
              <a
                key={i}
                href={url}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center gap-1 text-[10px] font-medium transition-colors"
                style={{ color: "#9a9ab8" }}
                onMouseEnter={(e) =>
                  ((e.currentTarget as HTMLElement).style.color = vendor.color)
                }
                onMouseLeave={(e) =>
                  ((e.currentTarget as HTMLElement).style.color = "#9a9ab8")
                }
                onClick={(e) => e.stopPropagation()}
              >
                <svg
                  className="w-2.5 h-2.5 shrink-0"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={2}
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"
                  />
                </svg>
                {getDomain(url)}
              </a>
            ))}
          </div>
        )}
      </div>
    </article>
  );
}

// ──────────────────────────────────────────────────────
// SECONDARY CARD — Clean editorial, no fake image area
// ──────────────────────────────────────────────────────
function SecondaryCard({ story }: { story: NewsItem }) {
  const { isHe } = useLang();
  const vendor = getVendor(story.vendor);
  const headline = isHe && story.headline_he ? story.headline_he : story.headline;
  const summary = isHe && story.summary_he ? story.summary_he : story.summary;

  return (
    <article
      id={`story-${story.story_id}`}
      className="group relative rounded-2xl overflow-hidden h-full flex flex-col story-card-hover"
      style={{
        background: "#ffffff",
        border: `1px solid ${vendor.color}22`,
        boxShadow: "0 1px 3px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.04)",
      }}
    >
      <OgImage src={story.og_image} vendor={story.vendor} vendorColor={vendor.color} height="180px" />

      {/* Thick vendor color top bar */}
      <div
        style={{
          height: "5px",
          background: `linear-gradient(90deg, ${vendor.color} 0%, ${vendor.color}aa 100%)`,
          flexShrink: 0,
        }}
      />

      <div className="flex flex-col gap-4 px-6 py-6 flex-1">
        {/* Top row: vendor icon + label */}
        <div className="flex items-center gap-2.5">
          <div
            style={{
              width: "36px",
              height: "36px",
              borderRadius: "9px",
              background: `linear-gradient(135deg, ${vendor.color}18, ${vendor.color}30)`,
              border: `1px solid ${vendor.color}25`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: vendor.color,
              flexShrink: 0,
              boxShadow: `0 2px 8px ${vendor.color}18`,
            }}
          >
            <CategoryIcon vendor={story.vendor} size={18} />
          </div>
          <div className="flex items-center gap-2">
            <span
              className="inline-flex items-center text-[10px] font-black px-2.5 py-0.5 rounded-full uppercase"
              style={{
                color: vendor.color,
                background: vendor.bg,
                border: `1px solid ${vendor.color}20`,
                letterSpacing: "0.13em",
                cursor: "pointer",
              }}
              onClick={(e) => { e.stopPropagation(); filterByVendor(story.vendor); }}
            >
              {vendor.label}
            </span>
            <SecondaryVendorBadge name={story.secondary_vendor} size="sm" />
            <StoryListenButton enUrl={story.summary_audio_url} heUrl={story.summary_audio_url_he} isHe={isHe} vendorColor={vendor.color} />
            {isToday(story.published_date) && (
              <span
                className="inline-flex items-center gap-1 text-[9px] font-black px-2 py-0.5 rounded-full uppercase"
                style={{
                  color: "#dc2626",
                  background: "rgba(220,38,38,0.08)",
                  border: "1px solid rgba(220,38,38,0.18)",
                  letterSpacing: "0.1em",
                }}
              >
                <span className="w-1.5 h-1.5 rounded-full shrink-0" style={{ backgroundColor: "#dc2626" }} />
                {isHe ? "חדש" : "NEW"}
              </span>
            )}
          </div>
          {story.source_count >= 1 && (
            <span
              className="ml-auto inline-flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full"
              style={{
                color: "#16a34a",
                background: "rgba(22,163,74,0.08)",
                border: "1px solid rgba(22,163,74,0.2)",
              }}
            >
              <span
                className="w-1 h-1 rounded-full shrink-0"
                style={{ backgroundColor: "#16a34a" }}
              />
              {story.source_count} {isHe ? "מקורות" : "sources"}
            </span>
          )}
        </div>

        {/* Headline */}
        <h2
          className="font-extrabold leading-snug tracking-tight transition-colors group-hover:text-indigo-600"
          style={{
            fontSize: "clamp(17px, 1.9vw, 21px)",
            color: "#0f0f1a",
            lineHeight: "1.22",
            letterSpacing: "-0.018em",
          }}
        >
          {headline}
        </h2>

        {/* Date */}
        <time
          className="text-[10px] font-semibold -mt-2"
          style={{ color: "#9a9ab8", fontFamily: "monospace" }}
        >
          {story.published_date}
        </time>

        {/* Summary */}
        <p
          className="leading-relaxed flex-1"
          style={{
            fontSize: "13.5px",
            color: "#3d3d5a",
            lineHeight: "1.7",
            display: "-webkit-box",
            WebkitBoxOrient: "vertical" as const,
            WebkitLineClamp: 6,
            overflow: "hidden",
          }}
        >
          {summary}
        </p>

        {/* Source links */}
        {story.urls && story.urls.length > 0 && (
          <div
            className="flex flex-wrap gap-x-4 gap-y-1 pt-3.5 mt-auto"
            style={{ borderTop: "1px solid #ededf5" }}
          >
            {story.urls.slice(0, 3).map((url, i) => (
              <a
                key={i}
                href={url}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center gap-1 text-[10px] font-medium transition-colors"
                style={{ color: "#9a9ab8" }}
                onMouseEnter={(e) =>
                  ((e.currentTarget as HTMLElement).style.color = vendor.color)
                }
                onMouseLeave={(e) =>
                  ((e.currentTarget as HTMLElement).style.color = "#9a9ab8")
                }
                onClick={(e) => e.stopPropagation()}
              >
                <svg
                  className="w-2.5 h-2.5 shrink-0"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={2}
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"
                  />
                </svg>
                {getDomain(url)}
              </a>
            ))}
          </div>
        )}
      </div>
    </article>
  );
}

// ──────────────────────────────────────────────────────
// REGULAR CARD — Clean minimal grid card with category icon
// ──────────────────────────────────────────────────────
function RegularCard({ story, rank }: { story: NewsItem; rank?: number }) {
  const { isHe } = useLang();
  const [expanded, setExpanded] = useState(false);
  const [clamped, setClamped] = useState(false);
  const summaryRef = useRef<HTMLParagraphElement>(null);
  const vendor = getVendor(story.vendor);
  const headline = isHe && story.headline_he ? story.headline_he : story.headline;
  const summary = isHe && story.summary_he ? story.summary_he : story.summary;
  useEffect(() => {
    const el = summaryRef.current;
    if (el) setClamped(el.scrollHeight > el.clientHeight);
  }, [summary]);

  return (
    <article
      id={`story-${story.story_id}`}
      className="group relative rounded-xl overflow-hidden h-full flex flex-col story-card-hover"
      style={{
        background: "#ffffff",
        border: `1px solid ${vendor.color}20`,
        boxShadow: "0 1px 3px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.04)",
        transition: "transform 0.2s ease, box-shadow 0.2s ease, border-color 0.2s ease",
        cursor: "pointer",
      }}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLElement).style.borderColor = `${vendor.color}55`;
        (e.currentTarget as HTMLElement).style.boxShadow = `0 4px 20px rgba(0,0,0,0.10), 0 0 0 1px ${vendor.color}22`;
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLElement).style.borderColor = `${vendor.color}20`;
        (e.currentTarget as HTMLElement).style.boxShadow = "0 1px 3px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.04)";
      }}
    >
      {/* Image or abstract gradient fallback */}
      <OgImage src={story.og_image} vendor={story.vendor} vendorColor={vendor.color} height="160px" />

      {/* Vendor color bar — full width */}
      <div
        style={{
          height: "4px",
          background: `linear-gradient(90deg, ${vendor.color} 0%, ${vendor.color}88 100%)`,
          flexShrink: 0,
        }}
      />

      <div className="flex flex-col gap-3 p-5 flex-1">
        {/* Top row: category icon + vendor badge + sources */}
        <div className="flex items-center gap-2">
          {/* Colored icon square */}
          <div
            style={{
              width: "34px",
              height: "34px",
              borderRadius: "9px",
              background: `linear-gradient(135deg, ${vendor.color}18, ${vendor.color}30)`,
              border: `1px solid ${vendor.color}25`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: vendor.color,
              flexShrink: 0,
              boxShadow: `0 2px 6px ${vendor.color}15`,
            }}
          >
            <CategoryIcon vendor={story.vendor} size={17} />
          </div>

          <span
            className="inline-flex items-center text-[10px] font-black px-2 py-0.5 rounded-full uppercase"
            style={{
              color: vendor.color,
              background: vendor.bg,
              border: `1px solid ${vendor.color}20`,
              letterSpacing: "0.12em",
              cursor: "pointer",
            }}
            onClick={(e) => { e.stopPropagation(); filterByVendor(story.vendor); }}
          >
            {vendor.label}
          </span>
          <SecondaryVendorBadge name={story.secondary_vendor} />
          <StoryListenButton enUrl={story.summary_audio_url} heUrl={story.summary_audio_url_he} isHe={isHe} vendorColor={vendor.color} />

          {isToday(story.published_date) && (
            <span
              className="inline-flex items-center gap-1 text-[9px] font-black px-2 py-0.5 rounded-full uppercase"
              style={{
                color: "#dc2626",
                background: "rgba(220,38,38,0.08)",
                border: "1px solid rgba(220,38,38,0.18)",
                letterSpacing: "0.1em",
              }}
            >
              <span className="w-1.5 h-1.5 rounded-full shrink-0" style={{ backgroundColor: "#dc2626" }} />
              {isHe ? "חדש" : "NEW"}
            </span>
          )}

          {story.source_count >= 1 && (
            <span
              className="ml-auto inline-flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full"
              style={{
                color: "#16a34a",
                background: "rgba(22,163,74,0.08)",
                border: "1px solid rgba(22,163,74,0.18)",
              }}
            >
              <span
                className="w-1 h-1 rounded-full shrink-0"
                style={{ backgroundColor: "#16a34a" }}
              />
              {story.source_count}
            </span>
          )}
        </div>

        {/* Headline — dominant, clickable to story page */}
        <h3
          className="font-extrabold leading-snug tracking-tight transition-colors group-hover:text-indigo-600"
          style={{
            fontSize: "16px",
            color: "#0f0f1a",
            lineHeight: "1.3",
            letterSpacing: "-0.015em",
            display: "-webkit-box",
            WebkitBoxOrient: "vertical" as const,
            WebkitLineClamp: 3,
            overflow: "hidden",
            cursor: "pointer",
          }}
          onClick={() => window.location.href = `/story/${story.story_id}/`}
        >
          {headline}
        </h3>

        {/* Date */}
        <time
          className="text-[10px] font-semibold -mt-1"
          style={{ color: "#9a9ab8", fontFamily: "monospace" }}
        >
          {story.published_date}
        </time>

        {/* Summary — expandable, clickable to story page when collapsed */}
        <p
          ref={summaryRef}
          className="leading-relaxed flex-1"
          style={{
            fontSize: "13px",
            color: "#6b6b8a",
            lineHeight: "1.68",
            cursor: "pointer",
            ...(expanded ? {} : {
              display: "-webkit-box",
              WebkitBoxOrient: "vertical" as const,
              WebkitLineClamp: 4,
              overflow: "hidden",
            }),
          }}
          onClick={() => window.location.href = `/story/${story.story_id}/`}
        >
          {summary}
        </p>
        {(clamped || expanded) && (
          <button
            onClick={(e) => { e.stopPropagation(); setExpanded((v) => !v); }}
            className="text-[11px] font-bold transition-colors self-start"
            style={{
              color: vendor.color,
              background: "none",
              border: "none",
              cursor: "pointer",
              padding: 0,
              marginTop: "-4px",
            }}
          >
            {expanded ? (isHe ? "הצג פחות" : "Show less") : (isHe ? "קרא עוד" : "Read more")}
          </button>
        )}

        {/* Source links */}
        {story.urls && story.urls.length > 0 && (
          <div
            className="flex flex-wrap gap-x-3 gap-y-1 pt-3 mt-auto"
            style={{ borderTop: "1px solid #ededf5" }}
          >
            {story.urls.slice(0, 3).map((url, i) => (
              <a
                key={i}
                href={url}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center gap-1 text-[10px] font-medium transition-colors"
                style={{ color: "#9a9ab8" }}
                onMouseEnter={(e) =>
                  ((e.currentTarget as HTMLElement).style.color = vendor.color)
                }
                onMouseLeave={(e) =>
                  ((e.currentTarget as HTMLElement).style.color = "#9a9ab8")
                }
                onClick={(e) => e.stopPropagation()}
              >
                <svg
                  className="w-2.5 h-2.5 shrink-0"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={2}
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"
                  />
                </svg>
                {getDomain(url)}
              </a>
            ))}
          </div>
        )}
      </div>
    </article>
  );
}

// ──────────────────────────────────────────────────────
// SIDEBAR CARD — Horizontal: image left, content right (hero sidebar)
// ──────────────────────────────────────────────────────
function SidebarCard({ story }: { story: NewsItem }) {
  const { isHe } = useLang();
  const [expanded, setExpanded] = useState(false);
  const [clamped, setClamped] = useState(false);
  const summaryRef = useRef<HTMLParagraphElement>(null);
  const vendor = getVendor(story.vendor);
  const headline = isHe && story.headline_he ? story.headline_he : story.headline;
  const summary = isHe && story.summary_he ? story.summary_he : story.summary;
  const urls = story.urls || [];
  useEffect(() => {
    const el = summaryRef.current;
    if (el) setClamped(el.scrollHeight > el.clientHeight);
  }, [summary]);

  return (
    <article
      id={`story-${story.story_id}`}
      className="group relative rounded-xl overflow-hidden h-full flex story-card-hover"
      style={{
        background: "#ffffff",
        border: `1px solid ${vendor.color}22`,
        boxShadow: "0 1px 6px rgba(0,0,0,0.04), 0 4px 16px rgba(0,0,0,0.03)",
        cursor: "pointer",
      }}
      onClick={() => window.location.href = `/story/${story.story_id}/`}
    >
      <OgImage src={story.og_image} vendor={story.vendor} vendorColor={vendor.color} height="100%" width="150px" />

      <div className={`flex flex-col gap-2 p-4 flex-1 ${expanded ? "" : "justify-center"}`}>
        <div className="flex items-center gap-2 flex-wrap">
          {/* Vendor icon box (parity with RegularCard) */}
          <div
            style={{
              width: "22px",
              height: "22px",
              borderRadius: "6px",
              background: `linear-gradient(135deg, ${vendor.color}18, ${vendor.color}30)`,
              border: `1px solid ${vendor.color}25`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: vendor.color,
              flexShrink: 0,
            }}
          >
            <CategoryIcon vendor={story.vendor} size={12} />
          </div>
          <span
            className="inline-flex items-center text-[10px] font-black px-2 py-0.5 rounded-full uppercase"
            style={{
              color: vendor.color,
              background: vendor.bg,
              border: `1px solid ${vendor.color}20`,
              letterSpacing: "0.12em",
            }}
            onClick={(e) => { e.stopPropagation(); filterByVendor(story.vendor); }}
          >
            {vendor.label}
          </span>
          <SecondaryVendorBadge name={story.secondary_vendor} size="sm" />
          <StoryListenButton enUrl={story.summary_audio_url} heUrl={story.summary_audio_url_he} isHe={isHe} vendorColor={vendor.color} />
          {/* Source count — show at >=1 (not just >1) so 1-source stories also surface their source */}
          {story.source_count >= 1 && (
            <span
              className="inline-flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full"
              style={{ color: "#16a34a", background: "rgba(22,163,74,0.08)", border: "1px solid rgba(22,163,74,0.18)" }}
            >
              {story.source_count} {isHe ? "מקורות" : "sources"}
            </span>
          )}
        </div>
        <h3
          className="font-bold leading-snug transition-colors group-hover:text-indigo-600"
          style={{
            fontSize: "15px",
            color: "#0f0f1a",
            lineHeight: "1.3",
            letterSpacing: "-0.015em",
            display: "-webkit-box",
            WebkitBoxOrient: "vertical" as const,
            WebkitLineClamp: 2,
            overflow: "hidden",
          }}
        >
          {headline}
        </h3>
        {summary && (
          <p
            ref={summaryRef}
            className="leading-relaxed"
            style={{
              fontSize: "12px",
              color: "#6b6b8a",
              lineHeight: "1.55",
              ...(expanded ? {} : {
                display: "-webkit-box",
                WebkitBoxOrient: "vertical" as const,
                WebkitLineClamp: 2,
                overflow: "hidden",
              }),
            }}
          >
            {summary}
          </p>
        )}
        {(clamped || expanded) && (
          <button
            onClick={(e) => { e.stopPropagation(); setExpanded((v) => !v); }}
            className="text-[11px] font-bold self-start"
            style={{ color: vendor.color, background: "none", border: "none", cursor: "pointer", padding: 0 }}
          >
            {expanded ? (isHe ? "הצג פחות" : "Show less") : (isHe ? "קרא עוד" : "Read more")}
          </button>
        )}
        {/* Source-domain chips (max 2) so the user can see WHO covered it without clicking through */}
        {urls.length > 0 && (
          <div className="flex items-center gap-1 flex-wrap">
            {urls.slice(0, 2).map((url, i) => (
              <a
                key={i}
                href={url}
                target="_blank"
                rel="noopener noreferrer"
                onClick={(e) => e.stopPropagation()}
                className="text-[10px] font-medium"
                style={{ color: "#9a9ab8", textDecoration: "underline" }}
              >
                {getDomain(url)}
              </a>
            ))}
            {urls.length > 2 && (
              <span className="text-[10px]" style={{ color: "#9a9ab8" }}>
                +{urls.length - 2}
              </span>
            )}
          </div>
        )}
        <time
          className="text-[10px] font-semibold"
          style={{ color: "#9a9ab8", fontFamily: "monospace" }}
        >
          {story.published_date}
        </time>
      </div>
    </article>
  );
}

export function StoryCard({ story, featured = false, secondary = false, sidebar = false, rank }: StoryCardProps) {
  if (featured) return <FeaturedCard story={story} />;
  if (sidebar) return <SidebarCard story={story} />;
  if (secondary) return <SecondaryCard story={story} />;
  return <RegularCard story={story} rank={rank} />;
}
